const { Agent } = require('@mastra/core/agent');
const { createWorkflow, createStep } = require('@mastra/core/workflows');
const { Mastra } = require('@mastra/core');
const { z } = require('zod');
const fs = require('fs');

async function main() {
  const recruiterAgent = new Agent({
    name: 'Recruiter Agent',
    instructions: 'You are an expert recruiter.',
    model: {
      provider: 'OPENAI',
      name: 'gpt-4o-mini',
    },
  });

  const gatherCandidateInfo = createStep({
    id: 'gatherCandidateInfo',
    outputSchema: z.object({
      candidateName: z.string(),
      isTechnical: z.boolean(),
      specialty: z.string(),
    }),
    execute: async ({ context }) => {
      const resumeText = context.getStepResult('trigger').resumeText;
      const response = await recruiterAgent.generate(
        `Parse the following resume and extract the candidate's name, whether they are technical (true/false), and their specialty: "${resumeText}"`,
        {
          output: z.object({
            candidateName: z.string(),
            isTechnical: z.boolean(),
            specialty: z.string(),
          }),
        }
      );
      return response.object;
    },
  });

  const askAboutSpecialty = createStep({
    id: 'askAboutSpecialty',
    outputSchema: z.object({
      question: z.string(),
    }),
    execute: async ({ context }) => {
      const info = context.getStepResult('gatherCandidateInfo');
      const response = await recruiterAgent.generate(
        `Generate a technical interview question for ${info.candidateName} about their specialty: ${info.specialty}`
      );
      return { question: response.text };
    },
  });

  const askAboutRole = createStep({
    id: 'askAboutRole',
    outputSchema: z.object({
      question: z.string(),
    }),
    execute: async ({ context }) => {
      const info = context.getStepResult('gatherCandidateInfo');
      const response = await recruiterAgent.generate(
        `Generate a question for ${info.candidateName} about what interests them in the role, considering their background in ${info.specialty}`
      );
      return { question: response.text };
    },
  });

  const recruiterWorkflow = createWorkflow({
    name: 'recruiter-workflow',
    triggerSchema: z.object({
      resumeText: z.string(),
    }),
  })
    .then(gatherCandidateInfo)
    .commit()
    .branch([
      [
        ({ context }) => {
          const info = context.getStepResult('gatherCandidateInfo');
          return info.isTechnical;
        },
        askAboutSpecialty,
      ],
      [
        ({ context }) => {
          const info = context.getStepResult('gatherCandidateInfo');
          return !info.isTechnical;
        },
        askAboutRole,
      ],
    ]);

  const mastra = new Mastra({
    workflows: {
      recruiterWorkflow,
    },
  });

  const candidates = [
    "Alice is a Software Engineer with 10 years of experience in React and Node.js.",
    "Bob is a Marketing Manager with 5 years of experience in SEO and content strategy.",
  ];

  const results = [];

  for (const resumeText of candidates) {
    console.log(`Running workflow for: ${resumeText}`);
    const { runId } = await recruiterWorkflow.execute({ triggerData: { resumeText } });
    const runResult = await recruiterWorkflow.getWorkflowRunById(runId);
    results.push(runResult);
  }

  fs.writeFileSync('/home/user/ai-recruiter/output.json', JSON.stringify(results, null, 2));
  console.log('Results saved to /home/user/ai-recruiter/output.json');
}

main().catch(console.error);

